def get_flat_dependant(dependant, *, skip_repeats=False, visited=None, parent_oauth_scopes=None):
    flat_dependant = Dependant(
        path_params=dependant.path_params.copy(),
        query_params=dependant.query_params.copy(),
        ...
    )
